"use client"

import * as React from "react"

import { NavUser } from "./nav-user"
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupContent,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@/components/ui/sidebar"

import {
  IconMailFilled,
  IconQuoteFilled,
  IconUserFilled,
  IconStarsFilled,
  IconBulbFilled,
  IconSearch,
  IconArchiveFilled,
} from "@tabler/icons-react";

// This is sample data
const data = {
  user: {
    name: "shadcn",
    email: "m@example.com",
    avatar: "/avatars/shadcn.jpg",
  },
  navMain: [
    {
      title: "Inbox",
      url: "/inbox",
      icon: IconMailFilled,
      isDisabled: true
    },
    {
      title: "Messages",
      url: "#",
      icon: IconQuoteFilled,
      isDisabled: true,
    },
    {
      title: "Profile",
      url: "#",
      icon: IconUserFilled,
      isDisabled: true,
    },
    {
      title: "AI",
      url: "#",
      icon: IconStarsFilled,
      isDisabled: true,
    },
    {
      title: "Ideas",
      url: "#",
      icon: IconBulbFilled,
      isDisabled: true,
    },
    {
      title: "Search",
      url: "#",
      icon: IconSearch,
      isDisabled: true,
    },
    {
      title: "Archive",
      url: "#",
      icon: IconArchiveFilled,
      isDisabled: true,
    },
  ],

}

export function AppSidebar({ ...props }: React.ComponentProps<typeof Sidebar>) {

  return (
    <Sidebar
      collapsible="icon"
      className="border-r p-2 group-data-[collapsible=icon]:p-0 bg-sidebar"
      {...props}
    >
      <SidebarHeader className="border-b max-md:py-4 py-4 flex items-center justify-start group-data-[collapsible=icon]:justify-center px-4 group-data-[collapsible=icon]:px-0">
        <SidebarMenu className="flex items-center justify-start group-data-[collapsible=icon]:items-center">
          <SidebarMenuItem className="flex items-center justify-start w-full group-data-[collapsible=icon]:justify-center">
            <SidebarMenuButton size="lg" className="group-data-[collapsible=icon]:h-10! group-data-[collapsible=icon]:w-10! group-data-[collapsible=icon]:p-0! flex items-center justify-start group-data-[collapsible=icon]:justify-center bg-orange-600 text-white rounded-lg shadow-[inset_0px_1px_2px_rgba(255,255,255,0.4),inset_0px_-2px_4px_rgba(0,0,0,0.3)] px-3 group-data-[collapsible=icon]:px-0 gap-2">
              <svg
                width="24"
                height="24"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2.5"
                strokeLinecap="round"
                strokeLinejoin="round"
                className="size-6"
              >
                <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5" />
              </svg>
              <span className="font-medium text-base  md:group-data-[collapsible=icon]:hidden">OceanLabs</span>
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarHeader>
      <SidebarContent>
        <SidebarGroup className="p-0">
          <SidebarGroupContent className="px-1.5 group-data-[collapsible=icon]:px-3">
            <SidebarMenu className="gap-3 py-4 flex flex-col items-start group-data-[collapsible=icon]:items-center px-2 group-data-[collapsible=icon]:px-0">
              {data.navMain.map((item) => {
                const isActive = item.title === "Inbox";
                return (
                  <SidebarMenuItem key={item.title} className="w-full">
                    <SidebarMenuButton
                      tooltip={{
                        children: item.title,
                        hidden: false,
                      }}
                      isActive={isActive}
                      className="group-data-[collapsible=icon]:h-10! max-md:h-10 group-data-[collapsible=icon]:w-10! group-data-[collapsible=icon]:p-0! flex items-center justify-start group-data-[collapsible=icon]:justify-center rounded-lg hover:bg-sidebar-accent transition-colors duration-200 data-[active=true]:bg-sidebar-accent data-[active=true]:border data-[active=true]:border-sidebar-border data-[active=true]:shadow-[inset_0px_2px_4px_rgba(0,0,0,0.3)] w-full gap-3 px-3 group-data-[collapsible=icon]:px-0"
                      asChild
                    >
                      <a
                        href={item.isDisabled ? "#" : item.url}
                        onClick={(e) => {
                          if (item.isDisabled) {
                            e.preventDefault();
                          }
                        }}
                        className="flex items-center justify-start group-data-[collapsible=icon]:justify-center text-sidebar-foreground/70 w-full gap-3"
                      >
                        <item.icon stroke={1.5} className="size-6! shrink-0 opacity-80" />
                        <span className="md:group-data-[collapsible=icon]:hidden font-medium">{item.title}</span>
                      </a>
                    </SidebarMenuButton>
                  </SidebarMenuItem>
                );
              })}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>
      </SidebarContent>
      <SidebarFooter className="pt-4 flex items-center justify-start group-data-[collapsible=icon]:justify-center px-2 group-data-[collapsible=icon]:px-0">
        <NavUser user={data.user} />
      </SidebarFooter>
    </Sidebar>
  )
}

export function EmptyState() {
  return (
    <div className="flex h-full items-center justify-center text-muted-foreground">
      Select an email to read
    </div>
  )
}

"use client"

import { cn } from "@/lib/utils"

export function WorkspaceLayout({
  list,
  content,
  isMailDetail = false,
}: {
  list: React.ReactNode
  content: React.ReactNode
  isMailDetail?: boolean
}) {
  return (
    <div className="flex h-screen overflow-hidden">
      {/* SECOND PANEL (LIST) */}
      <div className={cn(
        "w-full md:w-[350px] border-r bg-[#121212]",
        isMailDetail ? "hidden md:block" : "block"
      )}>
        {list}
      </div>

      {/* THIRD PANEL (CONTENT) */}
      <div className={cn(
        "flex-1 overflow-y-auto",
        isMailDetail ? "block" : "hidden md:block"
      )}>
        {content}
      </div>
    </div>
  )
}

"use client"

import { AppSidebar } from "./components/app-sidebar"
import {
    SidebarInset,
    SidebarProvider,
} from "@/components/ui/sidebar"

export function DashboardLayout({ children }: { children: React.ReactNode }) {
    return (
        <SidebarProvider className="bg-background"
            defaultOpen={false}
            style={{
                "--sidebar-width-icon": "4rem",
            } as React.CSSProperties}
        >
            <AppSidebar />
            <SidebarInset>
                {children}
            </SidebarInset>
        </SidebarProvider>
    )
}

"use client";

import { useState } from "react";
import { DashboardLayout } from "./dashboardLayout";
import { WorkspaceLayout } from "./components/mail/workspace-layout";
import { MailList } from "./components/mail/mail-list";
import { mails } from "./data";
import { MailViewer } from "./components/mail/mail-viewer";
import { IconMail } from "@tabler/icons-react";

function EmptyState() {
    return (
        <div className="h-full w-full bg-background flex flex-col items-center justify-center p-8">
            <div className="relative mb-12">
                <div className="absolute inset-0 bg-orange-500/10 blur-[100px] rounded-full" />
                <div className="relative size-24 rounded-3xl bg-card border border-border flex items-center justify-center shadow-2xl">
                    <IconMail className="size-10 text-orange-500 drop-shadow-[0_0_15px_rgba(249,115,22,0.4)]" />
                </div>
            </div>
        </div>
    );
}

export default function MailDashboardDemo() {
    const [selectedMailId, setSelectedMailId] = useState<string | null>(null);

    return (
        <DashboardLayout>
            <WorkspaceLayout
                isMailDetail={!!selectedMailId}
                list={
                    <MailList
                        mails={mails}
                        selectedMailId={selectedMailId}
                        onSelectMail={setSelectedMailId}
                    />
                }
                content={
                    selectedMailId ? (
                        <MailViewer id={selectedMailId} />
                    ) : (
                        <EmptyState />
                    )
                }
            />
        </DashboardLayout>
    );
}

import { WorkspaceLayout } from "./components/mail/workspace-layout"
import { MailList } from "./components/mail/mail-list"
import { mails } from "./data"

export default function InboxLayout({ children }: { children: React.ReactNode }) {
  return (
    <WorkspaceLayout
      list={<MailList mails={mails} />}
      content={children}
    />
  )
}

import { IconMail } from "@tabler/icons-react"

export default function Page() {
  return (
    <div className="h-full w-full bg-background flex flex-col items-center justify-center p-8">
      <div className="relative mb-12">
        <div className="absolute inset-0 bg-orange-500/10 blur-[100px] rounded-full" />
        <div className="relative size-24 rounded-3xl bg-card border border-border flex items-center justify-center shadow-2xl">
          <IconMail className="size-10 text-orange-500 drop-shadow-[0_0_15px_rgba(249,115,22,0.4)]" />
        </div>
      </div>
    </div>
  )
}

import { MailViewer } from "./components/mail/mail-viewer"

export default async function Page({ params }: { params: { id: string } }) {

   const { id } = await params
   return <MailViewer id={id} />
}
